#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>

#define MAX_ARGS 10
#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000

struct neighbor {
    char entry[REC_LENGTH];
    double dist;
};

__global__ void compute_distances(char *d_sandbox, float *d_z, int rec_count,
                                   float target_lat, float target_long) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < rec_count) {
        char *rec_iter = d_sandbox + (i * REC_LENGTH + LATITUDE_POS - 1);

        // Parse latitude
        float tmp_lat = 0.0f;
        float tmp_long = 0.0f;

        char *p = rec_iter;
        float sign = 1.0f;
        if (*p == '-') { sign = -1.0f; p++; }
        else if (*p == '+') { p++; }
        // skip spaces
        while (*p == ' ') p++;
        float val = 0.0f;
        while (*p >= '0' && *p <= '9') {
            val = val * 10.0f + (*p - '0');
            p++;
        }
        if (*p == '.') {
            p++;
            float frac = 0.1f;
            while (*p >= '0' && *p <= '9') {
                val += (*p - '0') * frac;
                frac *= 0.1f;
                p++;
            }
        }
        tmp_lat = sign * val;

        // Parse longitude (offset by 5 from rec_iter)
        p = rec_iter + 5;
        sign = 1.0f;
        if (*p == '-') { sign = -1.0f; p++; }
        else if (*p == '+') { p++; }
        while (*p == ' ') p++;
        val = 0.0f;
        while (*p >= '0' && *p <= '9') {
            val = val * 10.0f + (*p - '0');
            p++;
        }
        if (*p == '.') {
            p++;
            float frac = 0.1f;
            while (*p >= '0' && *p <= '9') {
                val += (*p - '0') * frac;
                frac *= 0.1f;
                p++;
            }
        }
        tmp_long = sign * val;

        float dlat = tmp_lat - target_lat;
        float dlon = tmp_long - target_long;
        d_z[i] = sqrtf(dlat * dlat + dlon * dlon);
    }
}

int main(int argc, char* argv[]) {
    long long time0 = clock();
    FILE   *flist, *fp;
    int    i=0, j=0, k=0, rec_count=0, done=0;
    char   sandbox[REC_LENGTH * REC_WINDOW], dbname[64];
    struct neighbor *neighbors = NULL;
    float target_lat, target_long;

    if(argc < 5) {
        fprintf(stderr, "Invalid set of arguments\n");
        exit(-1);
    }

    flist = fopen(argv[1], "r");
    if(!flist) {
        printf("error opening flist\n");
        exit(1);
    }

    k = atoi(argv[2]);
    target_lat = atof(argv[3]);
    target_long = atof(argv[4]);

    neighbors = (struct neighbor*)malloc(k * sizeof(struct neighbor));
    if(neighbors == NULL) {
        fprintf(stderr, "no room for neighbors\n");
        exit(0);
    }

    for(j = 0; j < k; j++) {
        neighbors[j].dist = OPEN;
    }

    if(fscanf(flist, "%s\n", dbname) != 1) {
        fprintf(stderr, "error reading filelist\n");
        exit(0);
    }

    fp = fopen(dbname, "r");
    if(!fp) {
        printf("error opening flist\n");
        exit(1);
    }

    float *z = (float*)malloc(REC_WINDOW * sizeof(float));

    // Allocate device memory
    char *d_sandbox;
    float *d_z;
    cudaMalloc((void**)&d_sandbox, REC_LENGTH * REC_WINDOW * sizeof(char));
    cudaMalloc((void**)&d_z, REC_WINDOW * sizeof(float));

    while(!done) {
        rec_count = fread(sandbox, REC_LENGTH, REC_WINDOW, fp);

        if(rec_count != REC_WINDOW) {
            if(!ferror(fp)) {
                // EOF on current file
                fclose(fp);
                fp = NULL;

                if(feof(flist)) {
                    done = 1;
                } else {
                    if(fscanf(flist, "%s\n", dbname) != 1) {
                        // No more files
                        done = 1;
                    } else {
                        fp = fopen(dbname, "r");
                        if(!fp) {
                            printf("error opening a db\n");
                            exit(1);
                        }
                    }
                }
            } else {
                perror("Error");
                exit(0);
            }
        }

        if(rec_count > 0) {
            // Copy sandbox to device
            cudaMemcpy(d_sandbox, sandbox, REC_LENGTH * rec_count * sizeof(char), cudaMemcpyHostToDevice);

            // Launch kernel
            int blockSize = 256;
            int gridSize = (rec_count + blockSize - 1) / blockSize;
            compute_distances<<<gridSize, blockSize>>>(d_sandbox, d_z, rec_count, target_lat, target_long);
            cudaDeviceSynchronize();

            // Copy results back
            cudaMemcpy(z, d_z, rec_count * sizeof(float), cudaMemcpyDeviceToHost);

            // Sequential nearest neighbor update
            for(i = 0; i < rec_count; i++) {
                float max_dist = -1;
                int max_idx = 0;
                for(j = 0; j < k; j++) {
                    if(neighbors[j].dist > max_dist) {
                        max_dist = neighbors[j].dist;
                        max_idx = j;
                    }
                }
                if(z[i] < neighbors[max_idx].dist) {
                    sandbox[(i+1)*REC_LENGTH-1] = '\0';
                    strcpy(neighbors[max_idx].entry, sandbox + i*REC_LENGTH);
                    neighbors[max_idx].dist = z[i];
                }
            }
        }
    }

    fprintf(stderr, "The %d nearest neighbors are:\n", k);
    for(j = 0; j < k; j++) {
        if(!(neighbors[j].dist == OPEN))
            fprintf(stderr, "%s --> %f\n", neighbors[j].entry, neighbors[j].dist);
    }

    fclose(flist);

    cudaFree(d_sandbox);
    cudaFree(d_z);
    free(z);
    free(neighbors);

    long long time1 = clock();
    printf("total time : %15.12f s", (float)(time1 - time0) / 1000000);
    return 0;
}
